import { useState, useEffect } from 'react'
import { useParams, Link, useNavigate, useLocation } from 'react-router-dom'
import { classes, enrolments, attendance, payments, settings as settingsApi } from '../api'
import { useApi } from '../hooks/useApi'
import { useAuth } from '../contexts/AuthContext'
import client from '../api/client'
import './AttendancePage.css'
import { fmt12 } from '../utils/time'

const AVATAR_COLORS = ['#b0a0ff', '#ccff00', '#ffaa00', '#ff88aa', '#44ffcc', '#ffcc88', '#b0f0b0', '#9ac4ff', '#ffb3de', '#44ff99']
function avatarColor(name) {
  let h = 0
  for (const c of (name || '')) h = (h * 31 + c.charCodeAt(0)) % AVATAR_COLORS.length
  return AVATAR_COLORS[h]
}

const STATUS_OPTS = [
  { value: 'pending',        label: 'Pending',             color: '#555' },
  { value: 'present',        label: 'Attended',            color: '#ccff00' },
  { value: 'late',           label: 'Late',                color: '#ffaa00' },
  { value: 'no_show',        label: 'No-show + $20 fee',   color: '#ff5050' },
  { value: 'no_show_waived', label: 'No-show — fee waived', color: '#ff8888' },
  { value: 'absent',         label: 'Excused / Absent',    color: '#666' },
  { value: 'cancelled',      label: 'Cancelled',           color: '#666' },
]
const STATUS_COLOR = Object.fromEntries(STATUS_OPTS.map(o => [o.value, o.color]))

const NOTE_TAGS = [
  { id: 'general', label: 'General', color: '#888' },
  { id: 'injury',  label: 'Injury',  color: '#ff8888' },
  { id: 'vibes',   label: 'Vibes',   color: '#b0a0ff' },
]
const NOTE_TAG_COLOR = Object.fromEntries(NOTE_TAGS.map(t => [t.id, t.color]))

function getMilestones(st, today) {
  const badges = []
  if (!st) return badges

  // Birthday
  if (st.date_of_birth) {
    const dob = new Date(st.date_of_birth)
    let thisYear = new Date(today.getFullYear(), dob.getMonth(), dob.getDate())
    // If birthday already passed this year, check next year's occurrence
    if (thisYear < today && !(thisYear.toDateString() === today.toDateString())) {
      thisYear = new Date(today.getFullYear() + 1, dob.getMonth(), dob.getDate())
    }
    const diff = Math.round((thisYear - today) / 86400000)
    if (diff === 0) badges.push({ label: 'Birthday today 🎂', color: '#ffaa00', bg: 'rgba(255,170,0,0.1)', border: 'rgba(255,170,0,0.35)' })
    else if (diff === 1) badges.push({ label: 'Birthday tomorrow 🎂', color: '#ffaa00', bg: 'rgba(255,170,0,0.08)', border: 'rgba(255,170,0,0.25)' })
    else if (diff > 1 && diff <= 7) badges.push({ label: `Birthday in ${diff} days 🎂`, color: '#ffaa00', bg: 'rgba(255,170,0,0.06)', border: 'rgba(255,170,0,0.2)' })
  }

  // Class count milestones — show when they've just hit a round number
  const count = st.total_classes_attended || 0
  const MILESTONES = [10, 25, 50, 75, 100, 150, 200, 300, 500]
  if (MILESTONES.includes(count)) {
    badges.push({ label: `${count} classes 🎉`, color: '#ccff00', bg: 'rgba(204,255,0,0.08)', border: 'rgba(204,255,0,0.25)' })
  }

  // Studio anniversary (years)
  if (st.date_joined) {
    const joined = new Date(st.date_joined)
    const years = today.getFullYear() - joined.getFullYear()
    if (years > 0) {
      const anniversary = new Date(today.getFullYear(), joined.getMonth(), joined.getDate())
      const diff = Math.round((anniversary - today) / 86400000)
      if (diff === 0) badges.push({ label: `${years} year${years !== 1 ? 's' : ''} at Duality 🥂`, color: '#b0a0ff', bg: 'rgba(176,160,255,0.1)', border: 'rgba(176,160,255,0.3)' })
    }
  }

  return badges
}

function enrollLabel(e, session) {
  const DAYS = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']
  if (e.enrolment_type === 'trial') return 'Trial class'
  if (e.enrolment_type === 'casual') return 'Casual class'
  if (e.enrolment_type === 'makeup') {
    const from = e.makeup_from_detail || e.original_session_detail
    if (from) return `Makeup — ${from.name} ${DAYS[from.day_of_week] || ''} ${fmt12(from.start_time)}`
    return 'Makeup session'
  }
  return 'Course enrolment'
}

function ConvertTrialModal({ enrolment: e, onClose, onSuccess }) {
  const { data: studioData } = useApi(() => settingsApi.get(), [])
  const studio = studioData?.data || studioData || {}
  const seasonPrice = parseFloat(studio.price_season || 270)
  const trialPrice = parseFloat(studio.price_trial || 35)
  const defaultAmount = Math.max(0, seasonPrice - trialPrice).toFixed(2)
  const [amount, setAmount] = useState('')
  const [paymentType, setPaymentType] = useState('payment')
  const [reference, setReference] = useState('')
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState(null)
  const amountVal = amount !== '' ? amount : defaultAmount

  async function handleSubmit(ev) {
    ev.preventDefault()
    setSaving(true)
    setError(null)
    try {
      await enrolments.convertTrial(e.id, {
        amount_paid: parseFloat(amountVal),
        payment_type: paymentType,
        reference,
        description: `Season enrolment — ${e.class_session_detail?.name || 'class'} (converted from trial)`,
      })
      onSuccess()
    } catch (err) {
      setError(err.response?.data?.detail || 'Conversion failed.')
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="modal-overlay" onClick={ev => ev.target === ev.currentTarget && onClose()}>
      <div className="modal-box" style={{ maxWidth: 420 }}>
        <div className="modal-title">
          Convert Trial → Full
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>
        <form onSubmit={handleSubmit} style={{ padding: '0 0 4px' }}>
          <div style={{ fontSize: 13, color: 'var(--grey)', marginBottom: 14, paddingBottom: 12, borderBottom: '1px solid var(--border)' }}>
            <b style={{ color: 'var(--white)' }}>{e.student_detail?.display_name}</b> · {e.class_session_detail?.name}
          </div>
          <div style={{ background: '#111', borderRadius: 8, padding: '10px 14px', fontSize: 12, color: 'var(--grey)', marginBottom: 14 }}>
            Season ${seasonPrice.toFixed(2)} − trial ${trialPrice.toFixed(2)} = <b style={{ color: 'var(--lime)' }}>${defaultAmount} remaining</b>
          </div>
          {error && <div style={{ background: 'rgba(255,68,68,0.1)', border: '1px solid rgba(255,68,68,0.3)', borderRadius: 8, padding: '10px 14px', fontSize: 13, color: 'var(--red)', marginBottom: 12 }}>{error}</div>}
          <div className="field"><label>Amount ($)</label><input type="number" step="0.01" min="0" value={amountVal} onChange={ev => setAmount(ev.target.value)} /></div>
          <div className="field"><label>Payment type</label>
            <select value={paymentType} onChange={ev => setPaymentType(ev.target.value)}>
              <option value="payment">Payment received</option>
              <option value="charge">Charge (invoice / owing)</option>
            </select>
          </div>
          <div className="field"><label>Reference <span style={{ color: 'var(--grey)', fontWeight: 400 }}>(optional)</span></label>
            <input value={reference} onChange={ev => setReference(ev.target.value)} placeholder="cash, Square #, etc." />
          </div>
          <div className="modal-footer">
            <button type="button" className="btn btn-ghost btn-sm" onClick={onClose}>Cancel</button>
            <button type="submit" className="btn btn-lime btn-sm" disabled={saving}>{saving ? 'Converting…' : `Confirm $${parseFloat(amountVal || 0).toFixed(2)}`}</button>
          </div>
        </form>
      </div>
    </div>
  )
}

function AddStudentModal({ sessionId, onClose, onAdded }) {
  const [query, setQuery] = useState('')
  const [results, setResults] = useState([])
  const [searching, setSearching] = useState(false)
  const [enrolType, setEnrolType] = useState('course')
  const [adding, setAdding] = useState(null)
  const [error, setError] = useState(null)

  useEffect(() => {
    if (!query.trim()) { setResults([]); return }
    const t = setTimeout(async () => {
      setSearching(true)
      try {
        const r = await client.get('/api/users/', { params: { search: query, role: 'student', limit: 10 } })
        setResults(r.data?.results || r.data || [])
      } finally { setSearching(false) }
    }, 300)
    return () => clearTimeout(t)
  }, [query])

  async function addStudent(student) {
    setAdding(student.id)
    setError(null)
    try {
      const r = await client.post('/api/enrolments/', { class_session: sessionId, student: student.id, enrolment_type: enrolType, status: 'active' })
      onAdded(r.data)
    } catch (err) {
      setError(err.response?.data?.detail || err.response?.data?.non_field_errors?.[0] || 'Could not add student.')
      setAdding(null)
    }
  }

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal-box" style={{ maxWidth: 460 }}>
        <div className="modal-title">Add Student<button className="modal-close" onClick={onClose}>✕</button></div>
        <div className="field">
          <label>Enrolment Type</label>
          <select value={enrolType} onChange={e => setEnrolType(e.target.value)}>
            <option value="course">Course enrolment</option>
            <option value="trial">Trial class</option>
            <option value="casual">Casual drop-in</option>
          </select>
        </div>
        <div className="field">
          <label>Search student</label>
          <input autoFocus placeholder="Name or email…" value={query} onChange={e => setQuery(e.target.value)} />
        </div>
        {error && <div style={{ fontSize: 13, color: 'var(--red)', marginBottom: 10 }}>{error}</div>}
        {searching && <div style={{ fontSize: 13, color: 'var(--grey)', marginBottom: 8 }}>Searching…</div>}
        {results.map(s => (
          <div key={s.id} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '10px 0', borderBottom: '1px solid #1e1e1e' }}>
            <div>
              <div style={{ fontWeight: 600, fontSize: 14 }}>{s.display_name || `${s.first_name} ${s.last_name}`}</div>
              <div style={{ fontSize: 12, color: 'var(--grey)' }}>{s.level || 'No level'} · {s.email}</div>
            </div>
            <button className="btn btn-lime btn-xs" disabled={adding === s.id} onClick={() => addStudent(s)}>
              {adding === s.id ? 'Adding…' : 'Add'}
            </button>
          </div>
        ))}
        <div className="modal-footer">
          <button className="btn btn-ghost btn-sm" onClick={onClose}>Close</button>
        </div>
      </div>
    </div>
  )
}

function ContactClassModal({ sessionId, occurrenceId, onClose }) {
  const [activeTab, setActiveTab] = useState('email')

  // Email tab state
  const [emailSubject, setEmailSubject] = useState('')
  const [emailBody, setEmailBody] = useState('')
  const [emailSending, setEmailSending] = useState(false)
  const [emailSent, setEmailSent] = useState(false)
  const [emailError, setEmailError] = useState(null)

  // Push tab state
  const [pushMessage, setPushMessage] = useState('')
  const [pushSending, setPushSending] = useState(false)
  const [pushSent, setPushSent] = useState(false)
  const [pushError, setPushError] = useState(null)

  // Popup tab state
  const [popupTitle, setPopupTitle] = useState('')
  const [popupMessage, setPopupMessage] = useState('')
  const [popupCtaLabel, setPopupCtaLabel] = useState('')
  const [popupCtaUrl, setPopupCtaUrl] = useState('')
  const [popupSending, setPopupSending] = useState(false)
  const [popupSent, setPopupSent] = useState(false)
  const [popupError, setPopupError] = useState(null)

  async function handleEmailSend(e) {
    e.preventDefault()
    setEmailSending(true)
    setEmailError(null)
    try {
      await client.post(`/api/classes/sessions/${sessionId}/email/`, {
        subject: emailSubject,
        body: emailBody,
        occurrence: occurrenceId,
        recipients: 'enrolled',
      })
      setEmailSent(true)
    } catch (err) {
      setEmailError(err.response?.data?.detail || 'Failed to send email.')
    } finally { setEmailSending(false) }
  }

  async function handlePushSend(e) {
    e.preventDefault()
    setPushSending(true)
    setPushError(null)
    try {
      await client.post(`/api/classes/sessions/${sessionId}/notify/`, {
        message: pushMessage,
        type: 'push',
      })
      setPushSent(true)
    } catch (err) {
      if (err.response?.status === 404) {
        setPushError("Push notifications aren't enabled yet on this server.")
      } else {
        setPushError(err.response?.data?.detail || 'Failed to send push notification.')
      }
    } finally { setPushSending(false) }
  }

  async function handlePopupSend(e) {
    e.preventDefault()
    setPopupSending(true)
    setPopupError(null)
    try {
      await client.post(`/api/classes/sessions/${sessionId}/notify/`, {
        title: popupTitle,
        message: popupMessage,
        cta_label: popupCtaLabel || undefined,
        cta_url: popupCtaUrl || undefined,
        type: 'popup',
      })
      setPopupSent(true)
    } catch (err) {
      if (err.response?.status === 404) {
        setPopupError("Push notifications aren't enabled yet on this server.")
      } else {
        setPopupError(err.response?.data?.detail || 'Failed to send pop-up alert.')
      }
    } finally { setPopupSending(false) }
  }

  const tabs = [
    { key: 'email', label: 'Email' },
    { key: 'push', label: 'Push Notification' },
    { key: 'popup', label: 'Pop-up Alert' },
  ]

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal-box" style={{ maxWidth: 520 }}>
        <div className="modal-title">
          Contact Class
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>

        {/* Tabs */}
        <div style={{ display: 'flex', borderBottom: '1px solid var(--border)', marginBottom: 16 }}>
          {tabs.map(t => (
            <button
              key={t.key}
              type="button"
              onClick={() => setActiveTab(t.key)}
              style={{
                background: 'none', border: 'none', cursor: 'pointer', padding: '8px 14px',
                fontSize: 13, fontWeight: 600,
                color: activeTab === t.key ? 'var(--lime)' : 'var(--grey)',
                borderBottom: `2px solid ${activeTab === t.key ? 'var(--lime)' : 'transparent'}`,
                marginBottom: -1,
              }}
            >{t.label}</button>
          ))}
        </div>

        {/* Email tab */}
        {activeTab === 'email' && (
          emailSent ? (
            <div>
              <div style={{ fontSize: 14, color: 'var(--lime)', marginBottom: 16 }}>✓ Email sent to enrolled students.</div>
              <div className="modal-footer"><button className="btn btn-ghost btn-sm" onClick={onClose}>Close</button></div>
            </div>
          ) : (
            <form onSubmit={handleEmailSend}>
              <div style={{ fontSize: 13, color: 'var(--grey)', marginBottom: 12 }}>Send an email to all enrolled students.</div>
              {emailError && <div style={{ fontSize: 13, color: 'var(--red)', marginBottom: 10 }}>{emailError}</div>}
              <div className="field"><label>Subject</label><input required value={emailSubject} onChange={e => setEmailSubject(e.target.value)} placeholder="e.g. Important update about today's class" /></div>
              <div className="field"><label>Message</label><textarea required rows={5} value={emailBody} onChange={e => setEmailBody(e.target.value)} placeholder="Your message…" /></div>
              <div className="modal-footer">
                <button type="button" className="btn btn-ghost btn-sm" onClick={onClose}>Cancel</button>
                <button type="submit" className="btn btn-lime btn-sm" disabled={emailSending}>{emailSending ? 'Sending…' : 'Send Email'}</button>
              </div>
            </form>
          )
        )}

        {/* Push tab */}
        {activeTab === 'push' && (
          pushSent ? (
            <div>
              <div style={{ fontSize: 14, color: 'var(--lime)', marginBottom: 16 }}>✓ Push notification sent.</div>
              <div className="modal-footer"><button className="btn btn-ghost btn-sm" onClick={onClose}>Close</button></div>
            </div>
          ) : (
            <form onSubmit={handlePushSend}>
              <div style={{ fontSize: 13, color: 'var(--grey)', marginBottom: 12 }}>Send a push notification to enrolled students' devices.</div>
              {pushError && <div style={{ fontSize: 13, color: 'var(--red)', marginBottom: 10, background: 'rgba(255,80,80,0.08)', border: '1px solid rgba(255,80,80,0.2)', borderRadius: 8, padding: '8px 12px' }}>{pushError}</div>}
              <div className="field">
                <label>Message <span style={{ color: 'var(--grey)', fontWeight: 400 }}>(max ~160 chars)</span></label>
                <textarea required rows={3} maxLength={200} value={pushMessage} onChange={e => setPushMessage(e.target.value)} placeholder="Short message sent to students' phones…" />
                <div style={{ fontSize: 11, color: 'var(--grey)', marginTop: 4 }}>{pushMessage.length}/160</div>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-ghost btn-sm" onClick={onClose}>Cancel</button>
                <button type="submit" className="btn btn-lime btn-sm" disabled={pushSending}>{pushSending ? 'Sending…' : 'Send Notification'}</button>
              </div>
            </form>
          )
        )}

        {/* Popup tab */}
        {activeTab === 'popup' && (
          popupSent ? (
            <div>
              <div style={{ fontSize: 14, color: 'var(--lime)', marginBottom: 16 }}>✓ Pop-up alert sent.</div>
              <div className="modal-footer"><button className="btn btn-ghost btn-sm" onClick={onClose}>Close</button></div>
            </div>
          ) : (
            <form onSubmit={handlePopupSend}>
              <div style={{ fontSize: 13, color: 'var(--grey)', marginBottom: 12 }}>Show a pop-up alert in the app to enrolled students.</div>
              {popupError && <div style={{ fontSize: 13, color: 'var(--red)', marginBottom: 10, background: 'rgba(255,80,80,0.08)', border: '1px solid rgba(255,80,80,0.2)', borderRadius: 8, padding: '8px 12px' }}>{popupError}</div>}
              <div className="field"><label>Title</label><input required value={popupTitle} onChange={e => setPopupTitle(e.target.value)} placeholder="e.g. Class update" /></div>
              <div className="field"><label>Message</label><textarea required rows={3} value={popupMessage} onChange={e => setPopupMessage(e.target.value)} placeholder="Your message…" /></div>
              <div className="field"><label>CTA Button Label <span style={{ color: 'var(--grey)', fontWeight: 400 }}>(optional)</span></label><input value={popupCtaLabel} onChange={e => setPopupCtaLabel(e.target.value)} placeholder="e.g. View details" /></div>
              <div className="field"><label>CTA URL <span style={{ color: 'var(--grey)', fontWeight: 400 }}>(optional)</span></label><input value={popupCtaUrl} onChange={e => setPopupCtaUrl(e.target.value)} placeholder="https://…" /></div>
              <div className="modal-footer">
                <button type="button" className="btn btn-ghost btn-sm" onClick={onClose}>Cancel</button>
                <button type="submit" className="btn btn-lime btn-sm" disabled={popupSending}>{popupSending ? 'Sending…' : 'Send Alert'}</button>
              </div>
            </form>
          )
        )}
      </div>
    </div>
  )
}

function CancelClassModal({ occurrence, session, onClose, onCancelled }) {
  const [reason, setReason] = useState('')
  const [notifyStudents, setNotifyStudents] = useState(true)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState(null)

  async function handleCancel(e) {
    e.preventDefault()
    if (!occurrence) { setError('No occurrence found for today.'); return }
    setSaving(true)
    setError(null)
    try {
      await client.patch(`/api/classes/occurrences/${occurrence.id}/`, { status: 'cancelled', notes: reason })
      if (notifyStudents && reason) {
        await client.post(`/api/classes/sessions/${session.id}/email/`, {
          subject: `Class cancelled — ${session.name}`,
          body: `Hi everyone,\n\n${session.name} on ${occurrence.date} has been cancelled.\n\n${reason ? `Reason: ${reason}\n\n` : ''}Sorry for any inconvenience.\n\nDuality Pole Studio`,
          occurrence: occurrence.id,
          recipients: 'all',
        }).catch(() => {})
      }
      onCancelled()
    } catch (err) {
      setError(err.response?.data?.detail || 'Could not cancel the class.')
      setSaving(false)
    }
  }

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal-box" style={{ maxWidth: 420 }}>
        <div className="modal-title" style={{ color: '#ff6b6b' }}>Cancel Class<button className="modal-close" onClick={onClose}>✕</button></div>
        <form onSubmit={handleCancel}>
          <div style={{ fontSize: 13, color: 'var(--grey)', marginBottom: 14 }}>
            This will cancel <b style={{ color: '#fff' }}>{session?.name}</b> for{' '}
            {occurrence ? new Date(occurrence.date + 'T00:00').toLocaleDateString('en-AU', { weekday: 'long', day: 'numeric', month: 'short' }) : 'today'} only.
          </div>
          {error && <div style={{ fontSize: 13, color: 'var(--red)', marginBottom: 10 }}>{error}</div>}
          <div className="field">
            <label>Reason <span style={{ color: 'var(--grey)', fontWeight: 400 }}>(optional)</span></label>
            <input value={reason} onChange={e => setReason(e.target.value)} placeholder="e.g. Instructor unwell" />
          </div>
          <div className="field">
            <label style={{ display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer' }}>
              <input type="checkbox" checked={notifyStudents} onChange={e => setNotifyStudents(e.target.checked)} style={{ accentColor: 'var(--lime)' }} />
              Email enrolled students
            </label>
          </div>
          <div className="modal-footer">
            <button type="button" className="btn btn-ghost btn-sm" onClick={onClose}>Keep Class</button>
            <button type="submit" className="btn btn-sm" style={{ background: 'rgba(255,107,107,0.15)', color: '#ff6b6b', border: '1px solid rgba(255,107,107,0.3)' }} disabled={saving}>
              {saving ? 'Cancelling…' : 'Confirm Cancel'}
            </button>
          </div>
        </form>
      </div>
    </div>
  )
}

export default function AttendancePage() {
  const { id } = useParams()
  const navigate = useNavigate()
  const location = useLocation()
  const { user } = useAuth()
  const isAdmin = user?.role === 'admin'
  const isAdminPath = location.pathname.startsWith('/admin/')

  const [session, setSession]         = useState(null)
  const [occurrence, setOccurrence]   = useState(null)
  const [occurrences, setOccurrences] = useState([])
  const [students, setStudents]       = useState([])
  const [cancelledStudents, setCancelledStudents] = useState([])
  const [waitlist, setWaitlist]       = useState([])
  const [register, setRegister]       = useState({})
  const [balances, setBalances]       = useState({})
  const [phones, setPhones]           = useState({})
  const [notes, setNotes]             = useState({})
  const [noteTags, setNoteTags]       = useState({})
  const [saving, setSaving]           = useState(false)
  const [saved, setSaved]             = useState(false)
  const [loading, setLoading]         = useState(true)
  const [tab, setTab]                 = useState('attending')
  const [noteModal, setNoteModal]     = useState(null)
  const [noteText, setNoteText]       = useState('')
  const [noteTag, setNoteTag]         = useState('')
  const [saveBanner, setSaveBanner]   = useState(false)
  const [convertEnrol, setConvertEnrol] = useState(null)
  const [addStudentModal, setAddStudentModal] = useState(false)
  const [capacityOverride, setCapacityOverride] = useState(null)
  const [contactModal, setContactModal] = useState(false)
  const [cancelClassModal, setCancelClassModal] = useState(false)

  const today = new Date()

  async function loadOccurrence(occ) {
    setOccurrence(occ)
    setSaved(false)
    if (!occ) return
    try {
      const attRes = await attendance.list({ occurrence: occ.id })
      const initial = {}
      const initialNotes = {}
      const initialNoteTags = {}
      for (const r of (attRes.data.results || [])) {
        initial[r.student] = r.status === 'no_show' && r.no_show_fee_waived ? 'no_show_waived' : r.status
        initialNotes[r.student] = r.note || ''
        initialNoteTags[r.student] = r.note_tag || ''
      }
      // Default to pending for unrecorded students
      setStudents(prev => {
        for (const e of prev) {
          if (!initial[e.student]) initial[e.student] = 'pending'
        }
        return prev
      })
      setRegister(initial)
      setNotes(initialNotes)
      setNoteTags(initialNoteTags)
    } catch {
      // silently fail
    }
  }

  useEffect(() => {
    async function load() {
      setLoading(true)
      try {
        const [sessRes, occRes, enrolRes, cancelledRes] = await Promise.all([
          classes.get(id),
          classes.occurrences({ session: id }),
          enrolments.list({ session: id, status: 'active' }),
          enrolments.list({ session: id, status: 'cancelled' }),
        ])
        const s = sessRes.data
        const occs = occRes.data.results || []
        const todayStr = new Date().toISOString().slice(0, 10)
        const occ = occs.find(o => o.date === todayStr) || occs[0] || null
        setSession(s)
        setOccurrence(occ)
        setOccurrences(occs)

        const enrolled = enrolRes.data.results || []
        const cancelled = cancelledRes.data.results || []
        setStudents(enrolled)
        setCancelledStudents(cancelled)

        const initial = {}
        const initialNotes = {}
        const initialNoteTags = {}
        if (occ) {
          const attRes = await attendance.list({ occurrence: occ.id })
          for (const r of (attRes.data.results || [])) {
            initial[r.student] = r.status === 'no_show' && r.no_show_fee_waived ? 'no_show_waived' : r.status
            initialNotes[r.student] = r.note || ''
            initialNoteTags[r.student] = r.note_tag || ''
          }

          // Load waitlist
          try {
            const wlRes = await client.get('/api/classes/waitlist/', { params: { occurrence: occ.id } })
            setWaitlist(wlRes.data?.results || [])
          } catch {
            try {
              const wlRes2 = await client.get('/api/classes/waitlist/', { params: { session: id } })
              setWaitlist(wlRes2.data?.results || [])
            } catch { setWaitlist([]) }
          }
        }
        // Default to pending (not present) for unrecorded students
        for (const e of enrolled) {
          if (!initial[e.student]) initial[e.student] = 'pending'
        }
        setRegister(initial)
        setNotes(initialNotes)
        setNoteTags(initialNoteTags)

        const balMap = {}
        const phoneMap = {}
        await Promise.all(enrolled.map(async e => {
          try {
            const res = await payments.balance(e.student)
            balMap[e.student] = parseFloat(res.data.balance)
          } catch { balMap[e.student] = 0 }
          if (e.student_detail?.phone) phoneMap[e.student] = e.student_detail.phone
        }))
        setBalances(balMap)
        setPhones(phoneMap)
      } finally {
        setLoading(false)
      }
    }
    load()
  }, [id])

  function setStatus(studentId, status) {
    setRegister(r => ({ ...r, [studentId]: status }))
    setSaved(false)
  }

  function markAllPresent() {
    const all = {}
    students.forEach(e => { all[e.student] = 'present' })
    setRegister(all)
    setSaved(false)
  }

  async function handleSave() {
    if (!occurrence) return
    setSaving(true)
    try {
      const records = students.map(e => {
        const raw = register[e.student] || 'pending'
        return {
          student: e.student,
          status: raw === 'no_show_waived' ? 'no_show' : raw,
          no_show_fee_charged: raw === 'no_show',
          no_show_fee_waived: raw === 'no_show_waived',
          note: notes[e.student] || '',
          note_tag: noteTags[e.student] || '',
        }
      })
      await attendance.bulkSave(occurrence.id, records)
      setSaved(true)
      setSaveBanner(true)
    } finally {
      setSaving(false)
    }
  }

  const awayStatuses = ['no_show', 'no_show_waived', 'absent', 'cancelled']
  const attendingStudents = students.filter(e => !awayStatuses.includes(register[e.student] || 'pending'))
  const awayStudents = students.filter(e => awayStatuses.includes(register[e.student] || 'pending'))

  const counts = {
    present: Object.values(register).filter(v => v === 'present').length,
    late: Object.values(register).filter(v => v === 'late').length,
    no_show: Object.values(register).filter(v => v === 'no_show' || v === 'no_show_waived').length,
    absent: Object.values(register).filter(v => v === 'absent').length,
    cancelled: Object.values(register).filter(v => v === 'cancelled').length,
  }

  // Week number helper
  function getWeekNum(occ) {
    if (!session?.season_start_date || !occ?.date) return null
    return Math.ceil((new Date(occ.date) - new Date(session.season_start_date)) / (7 * 24 * 60 * 60 * 1000)) + 1
  }

  function formatOccDate(occ) {
    if (!occ?.date) return ''
    const d = new Date(occ.date + 'T00:00')
    return d.toLocaleDateString('en-AU', { day: 'numeric', month: 'short' }).replace(' ', ' ')
  }

  const totalWeeks = session?.season_start_date && session?.season_end_date
    ? Math.round((new Date(session.season_end_date) - new Date(session.season_start_date)) / (7 * 24 * 60 * 60 * 1000))
    : null

  const currentWeekNum = getWeekNum(occurrence)
  const showWeekSelector = session?.season_start_date && occurrences.length > 1

  if (loading) return <div className="loading-center"><div className="spinner" /></div>

  const shownStudents = tab === 'attending' ? attendingStudents : awayStudents
  const isCancelledTab = tab === 'cancelled'

  return (
    <div className="att-page">
      {/* Header */}
      <div style={{ marginBottom: 20 }}>
        {/* Back link */}
        {isAdminPath ? (
          <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 12 }}>
            <button onClick={() => navigate('/admin/timetable')} style={{ background: 'none', border: 'none', color: 'var(--grey)', fontSize: 12, cursor: 'pointer', padding: 0 }}>← Timetable</button>
            <Link to={`/admin/classes/${id}`} style={{ fontSize: 12, color: 'var(--lime)', textDecoration: 'none' }}>Edit Class</Link>
            <Link to={`/admin/classes/${id}/season-enrolments`} style={{ fontSize: 12, color: 'var(--lav)', textDecoration: 'none' }}>Season Enrolments</Link>
          </div>
        ) : (
          <Link to="/classes" style={{ fontSize: 12, color: 'var(--grey)', display: 'inline-block', marginBottom: 10, textDecoration: 'none' }}>← My Classes</Link>
        )}

        {/* Class info card */}
        <div style={{ background: '#111', border: '1px solid var(--border, #222)', borderRadius: 12, padding: '16px 20px', marginBottom: 16 }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 12 }}>
            <div>
              <div style={{ fontFamily: "'Archivo Black', sans-serif", fontSize: 20, lineHeight: 1.2 }}>{session?.name}</div>
              <div style={{ fontSize: 13, color: 'var(--grey)', marginTop: 6, display: 'flex', gap: 16, flexWrap: 'wrap', alignItems: 'center' }}>
                {occurrence && (
                  <span style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    <span>{new Date(occurrence.date + 'T00:00').toLocaleDateString('en-AU', { weekday: 'long', day: 'numeric', month: 'short', year: 'numeric' })}</span>
                    {showWeekSelector && (
                      <select
                        value={occurrence?.id || ''}
                        onChange={e => {
                          const selected = occurrences.find(o => String(o.id) === String(e.target.value))
                          if (selected) loadOccurrence(selected)
                        }}
                        style={{
                          background: '#1a1a1a', border: '1px solid var(--border)', borderRadius: 6,
                          color: 'var(--grey)', fontSize: 11, padding: '2px 6px', cursor: 'pointer', outline: 'none',
                        }}
                      >
                        {occurrences.map(o => {
                          const wn = getWeekNum(o)
                          return (
                            <option key={o.id} value={o.id}>
                              Week {wn}{totalWeeks ? ` / ${totalWeeks}` : ''} — {formatOccDate(o)}{o.status === 'cancelled' ? ' (cancelled)' : ''}
                            </option>
                          )
                        })}
                      </select>
                    )}
                  </span>
                )}
                {session?.start_time && <span>{fmt12(session.start_time)}</span>}
                {session?.instructor_detail?.display_name && <span>{session.instructor_detail.display_name}</span>}
                {session?.studio_detail?.name && <span>{session.studio_detail.name}</span>}
              </div>
            </div>
            <div style={{ textAlign: 'right' }}>
              <div style={{ fontFamily: "'Archivo Black', sans-serif", fontSize: 22, color: students.length >= (capacityOverride ?? session?.capacity ?? 0) ? '#ff6b6b' : 'var(--lime)' }}>
                {students.length} / {capacityOverride ?? session?.capacity ?? '—'}
              </div>
              <div style={{ fontSize: 11, color: 'var(--grey)' }}>enrolled</div>
            </div>
          </div>
        </div>

        {/* Week selector tiles */}
        {showWeekSelector && (
          <div style={{ overflowX: 'auto', WebkitOverflowScrolling: 'touch', scrollbarWidth: 'none', marginBottom: 16 }}>
            <div style={{ display: 'flex', gap: 8, paddingBottom: 4, minWidth: 'max-content' }}>
              {occurrences.map(occ => {
                const wn = getWeekNum(occ)
                const isActive = occurrence?.id === occ.id
                const isCancelled = occ.status === 'cancelled'
                return (
                  <button
                    key={occ.id}
                    onClick={() => loadOccurrence(occ)}
                    style={{
                      background: isCancelled ? 'rgba(255,80,80,0.08)' : isActive ? 'rgba(204,255,0,0.08)' : '#111',
                      border: `1px solid ${isActive ? 'var(--lime)' : isCancelled ? 'rgba(255,80,80,0.3)' : 'var(--border)'}`,
                      borderRadius: 10,
                      padding: '8px 14px',
                      cursor: 'pointer',
                      textAlign: 'center',
                      minWidth: 72,
                      flexShrink: 0,
                    }}
                  >
                    <div style={{ fontSize: 12, fontWeight: 700, color: isActive ? 'var(--lime)' : isCancelled ? '#ff6b6b' : 'var(--grey)', marginBottom: 2 }}>
                      Week {wn}
                    </div>
                    <div style={{ fontSize: 11, color: isActive ? 'var(--lime)' : isCancelled ? '#ff6b6b' : '#555' }}>
                      {formatOccDate(occ)}
                    </div>
                  </button>
                )
              })}
            </div>
          </div>
        )}

        {/* Action bar */}
        <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginBottom: 8 }}>
          <button className="btn btn-lime btn-sm" onClick={markAllPresent}>Mark All Present</button>
          <button className={`btn btn-sm ${saved ? 'btn-ghost' : 'btn-ghost'}`} style={{ border: '1px solid var(--border)' }} onClick={handleSave} disabled={saving || !occurrence}>
            {saving ? <span className="spinner" style={{ width: 14, height: 14 }} /> : saved ? '✓ Saved' : 'Save Register'}
          </button>
          {isAdminPath && (
            <>
              <button className="btn btn-ghost btn-sm" onClick={() => setAddStudentModal(true)}>+ Add Student</button>
              <button className="btn btn-ghost btn-sm" onClick={() => {
                const newCap = prompt('New capacity override:', capacityOverride ?? session?.capacity ?? '')
                if (newCap && !isNaN(parseInt(newCap))) setCapacityOverride(parseInt(newCap))
              }}>Override Capacity</button>
              <button className="btn btn-ghost btn-sm" onClick={() => setContactModal(true)}>Contact Class</button>
              <button className="btn btn-ghost btn-sm" style={{ color: '#ff6b6b', borderColor: 'rgba(255,107,107,0.3)' }} onClick={() => setCancelClassModal(true)}>Cancel Class</button>
            </>
          )}
        </div>
      </div>

      {/* Save banner */}
      {saveBanner && (
        <div style={{ background: 'rgba(204,255,0,0.08)', border: '1px solid rgba(204,255,0,0.25)', borderRadius: 10, padding: '12px 16px', marginBottom: 16, fontSize: 13, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span>Register saved — {counts.present} attended{counts.late > 0 ? `, ${counts.late} late` : ''}{counts.no_show > 0 ? `, ${counts.no_show} no-show` : ''}</span>
          <button style={{ background: 'none', border: 'none', color: 'var(--grey)', cursor: 'pointer', fontSize: 16 }} onClick={() => setSaveBanner(false)}>✕</button>
        </div>
      )}

      {/* Stats strip */}
      <div className="att-stats-row" style={{ marginBottom: 20 }}>
        {[
          ['Enrolled', students.length, '#fff'],
          ['Attended', counts.present, '#ccff00'],
          ['Late', counts.late, '#ffaa00'],
          ['No-show', counts.no_show, '#ff5050'],
          ['Absent', counts.absent, '#555'],
          ['Waitlist', waitlist.length, 'var(--lav)'],
        ].map(([label, val, color]) => (
          <div key={label} className="att-stat-chip">
            <div style={{ fontFamily: "'Archivo Black', sans-serif", fontSize: 22, color, lineHeight: 1 }}>{val}</div>
            <div style={{ fontSize: 10, color: '#555', textTransform: 'uppercase', letterSpacing: '0.5px', marginTop: 4 }}>{label}</div>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div style={{ display: 'flex', borderBottom: '1px solid #1e1e1e', marginBottom: 16, overflowX: 'auto', WebkitOverflowScrolling: 'touch', scrollbarWidth: 'none' }}>
        {[
          ['attending', `Register (${attendingStudents.length})`],
          ['waitlist', `Waitlist (${waitlist.length})`],
          ['away', `Away (${awayStudents.length})`],
          ['cancelled', `Cancelled (${cancelledStudents.length})`],
        ].map(([key, label]) => (
          <button
            key={key}
            onClick={() => setTab(key)}
            style={{
              padding: '10px 14px', border: 'none', background: 'transparent',
              fontSize: 13, fontWeight: 600, cursor: 'pointer', flexShrink: 0,
              whiteSpace: 'nowrap',
              color: tab === key ? 'var(--lime)' : 'var(--grey)',
              borderBottom: `2px solid ${tab === key ? 'var(--lime)' : 'transparent'}`,
              marginBottom: -1,
            }}
          >
            {label}
          </button>
        ))}
      </div>

      {/* Waitlist tab */}
      {tab === 'waitlist' && (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          {waitlist.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '48px 0', color: 'var(--grey)', fontSize: 13 }}>No one on the waitlist</div>
          ) : waitlist.map((entry, i) => {
            const st = entry.student_detail || entry.student
            return (
              <div key={entry.id || i} style={{ display: 'flex', alignItems: 'center', gap: 12, background: '#111', border: '1px solid #1e1e1e', borderRadius: 12, padding: '14px 16px' }}>
                <div style={{ width: 28, height: 28, borderRadius: '50%', background: '#1a1a1a', border: '1px solid #333', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 12, fontWeight: 700, color: 'var(--lav)', flexShrink: 0 }}>
                  {entry.position || i + 1}
                </div>
                <div className="avatar" style={{ background: avatarColor(st?.display_name || st?.first_name || ''), flexShrink: 0 }}>
                  {(st?.first_name || st?.display_name || '?')[0]}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 600, fontSize: 14 }}>{st?.display_name || `${st?.first_name || ''} ${st?.last_name || ''}`.trim()}</div>
                  <div style={{ fontSize: 12, color: 'var(--grey)', marginTop: 2 }}>
                    {entry.waitlist_type === 'season' ? 'Full season waitlist' : 'Casual spot waitlist'}
                    {entry.created_at && <span style={{ marginLeft: 8 }}>· Joined {new Date(entry.created_at).toLocaleDateString('en-AU', { day: 'numeric', month: 'short' })}</span>}
                  </div>
                </div>
                <span style={{ fontSize: 10, fontWeight: 700, background: 'rgba(176,160,255,0.1)', color: 'var(--lav)', borderRadius: 6, padding: '3px 8px' }}>#{entry.position || i + 1}</span>
              </div>
            )
          })}
        </div>
      )}

      {/* Cancelled tab */}
      {tab === 'cancelled' && (
        <div className="tbl-section">
          {cancelledStudents.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '48px 0', color: 'var(--grey)', fontSize: 13 }}>No cancelled enrolments</div>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>Student</th>
                  <th>Level</th>
                  <th>Type</th>
                  <th>Cancelled</th>
                </tr>
              </thead>
              <tbody>
                {cancelledStudents.map(e => {
                  const st = e.student_detail
                  return (
                    <tr key={e.id}>
                      <td>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                          <div className="avatar" style={{ background: avatarColor(st?.display_name || ''), width: 28, height: 28, fontSize: 12, flexShrink: 0 }}>
                            {st?.first_name?.[0] || '?'}
                          </div>
                          <div>
                            <div
                              style={{ fontWeight: 600, fontSize: 14, cursor: 'pointer', textDecoration: 'underline', textDecorationColor: 'rgba(255,255,255,0.2)' }}
                              onClick={() => navigate(isAdminPath ? `/admin/students/${e.student}` : `/students/${e.student}`)}
                            >{st?.display_name}</div>
                            {st?.pronouns && <div style={{ fontSize: 11, color: '#555' }}>{st.pronouns}</div>}
                          </div>
                        </div>
                      </td>
                      <td style={{ color: 'var(--grey)', fontSize: 12 }}>{st?.level || '—'}</td>
                      <td>
                        <span style={{ fontSize: 11, fontWeight: 700, padding: '2px 8px', borderRadius: 4, background: '#1a1a1a', color: '#888' }}>
                          {e.enrolment_type === 'trial' ? 'Trial' : e.enrolment_type === 'casual' ? 'Casual' : 'Enrolled'}
                        </span>
                      </td>
                      <td style={{ color: 'var(--grey)', fontSize: 12 }}>
                        {e.cancelled_date ? new Date(e.cancelled_date).toLocaleDateString('en-AU', { day: 'numeric', month: 'short', year: 'numeric' }) : '—'}
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          )}
        </div>
      )}

      {/* Attending / Away tabs — table for admin, cards for others */}
      {tab !== 'waitlist' && tab !== 'cancelled' && (
        <>
          {shownStudents.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '48px 0', color: 'var(--grey)', fontSize: 13 }}>
              {tab === 'attending' ? 'No students attending' : 'No one marked away or cancelled'}
            </div>
          ) : isAdminPath ? (
            /* ── Admin table view ── */
            <div className="tbl-section">
              <table>
                <thead>
                  <tr>
                    <th style={{ minWidth: 200 }}>Student</th>
                    <th>Type</th>
                    <th>Contact</th>
                    <th style={{ minWidth: 180 }}>Status</th>
                    <th>Balance</th>
                    <th style={{ minWidth: 160 }}>Notes</th>
                  </tr>
                </thead>
                <tbody>
                  {shownStudents.map(e => {
                    const st = e.student_detail
                    const status = register[e.student] || 'pending'
                    const balance = balances[e.student]
                    const noteText_ = notes[e.student] || ''
                    const milestones = getMilestones(st, today)
                    const isFirstTime = e.is_first_class || e.classes_attended === 0 || e.total_attendance === 0

                    return (
                      <tr key={e.student}>
                        {/* Student */}
                        <td>
                          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
