        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16, marginBottom: 16 }}>
          <div>
            <label style={labelStyle}>Season</label>
            <select style={inputStyle} value={form.season} onChange={e => set('season', e.target.value)}>
