import { useState } from 'react'
import { Link, useNavigate, useLocation } from 'react-router-dom'
import { auth, forms } from '../api'
import { useAuth } from '../contexts/AuthContext'
import './LoginPage.css'

const WAIVER_TEXT = `DUALITY POLE STUDIO — LIABILITY WAIVER & STUDIO AGREEMENT

By signing this waiver, you acknowledge the following:

PHYSICAL ACTIVITY & RISK
Pole dancing, aerial arts, and dance activities carry inherent risks including, but not limited to, falls, muscle strains, bruising, and other physical injuries. You voluntarily assume all risks associated with participation in classes and activities at Duality Pole Studio.

HEALTH & FITNESS
You confirm that you are in good health and physically capable of participating in the activities you have enrolled in. You agree to inform your instructor of any injuries, health conditions, or physical limitations before class. If you are unsure whether an activity is appropriate for you, please consult a healthcare professional before participating.

LIABILITY RELEASE
You release Duality Pole Studio, its instructors, staff, and owners from any liability for injuries, loss, or damage arising from your participation in classes or use of studio facilities, except where caused by gross negligence or intentional misconduct.

STUDIO RULES & CODE OF CONDUCT
You agree to:
• Treat all students, instructors and staff with respect
• Follow instructor guidance and studio safety protocols at all times
• Not attend classes under the influence of alcohol or drugs
• Wear appropriate attire as directed for each class style
• Report any equipment concerns to staff immediately
• Respect the privacy of other students — no photography or recording without consent

CANCELLATION & REFUND POLICY
You acknowledge that you have read and understood the studio's cancellation, refund, and enrolment policies, including that season enrolments are non-refundable once a season has commenced.

MINIMUM AGE
You confirm that you are 18 years of age or older. The studio reserves the right to request identification to verify age.

PHOTO & SOCIAL MEDIA
Unless you opt out, you consent to photos or videos taken during classes being used for studio promotional purposes, including social media. You can withdraw this consent at any time by contacting the studio.`

function Step1({ form, setField, onNext, errors }) {
  function validate() {
    const errs = {}
    if (!form.first_name.trim()) errs.first_name = 'Required'
    if (!form.last_name.trim()) errs.last_name = 'Required'
    if (!form.email.trim()) errs.email = 'Required'
    if (!form.password || form.password.length < 8) errs.password = 'Minimum 8 characters'
    if (!form.date_of_birth) { errs.date_of_birth = 'Required'; }
    else {
      const dob = new Date(form.date_of_birth)
      const cutoff = new Date()
      cutoff.setFullYear(cutoff.getFullYear() - 18)
      if (dob > cutoff) errs.date_of_birth = 'You must be 18 or older to sign up'
    }
    if (!form.phone.trim()) errs.phone = 'Required'
    return errs
  }

  function handleNext(e) {
    e.preventDefault()
    const errs = validate()
    if (Object.keys(errs).length) { onNext(errs); return }
    onNext({})
  }

  return (
    <form onSubmit={handleNext}>
      {errors.general && <div className="error-msg" style={{ marginBottom: 12 }}>{errors.general}</div>}

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 14 }}>
        <div className="field">
          <label>First name</label>
          <input type="text" value={form.first_name} onChange={e => setField('first_name', e.target.value)} autoFocus required />
          {errors.first_name && <div className="error-msg" style={{ marginTop: 4, fontSize: 12 }}>{errors.first_name}</div>}
        </div>
        <div className="field">
          <label>Last name</label>
          <input type="text" value={form.last_name} onChange={e => setField('last_name', e.target.value)} required />
          {errors.last_name && <div className="error-msg" style={{ marginTop: 4, fontSize: 12 }}>{errors.last_name}</div>}
        </div>
      </div>

      <div className="field" style={{ marginBottom: 14 }}>
        <label>Email</label>
        <input type="email" value={form.email} onChange={e => setField('email', e.target.value)} autoComplete="email" required />
        {errors.email && <div className="error-msg" style={{ marginTop: 4, fontSize: 12 }}>{errors.email}</div>}
      </div>

      <div className="field" style={{ marginBottom: 14 }}>
        <label>Password</label>
        <input type="password" value={form.password} onChange={e => setField('password', e.target.value)} autoComplete="new-password" minLength={8} required />
        {errors.password && <div className="error-msg" style={{ marginTop: 4, fontSize: 12 }}>{errors.password}</div>}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 14 }}>
        <div className="field">
          <label>Date of birth</label>
          <input type="date" value={form.date_of_birth} onChange={e => setField('date_of_birth', e.target.value)} required />
          {errors.date_of_birth && <div className="error-msg" style={{ marginTop: 4, fontSize: 12 }}>{errors.date_of_birth}</div>}
        </div>
        <div className="field">
          <label>Phone</label>
          <input type="tel" value={form.phone} onChange={e => setField('phone', e.target.value)} placeholder="04xx xxx xxx" required />
          {errors.phone && <div className="error-msg" style={{ marginTop: 4, fontSize: 12 }}>{errors.phone}</div>}
        </div>
      </div>

      <button type="submit" className="btn btn-lime" style={{ width: '100%', marginTop: 4 }}>
        Continue →
      </button>
    </form>
  )
}

function Step2({ form, setField, onNext, onBack, errors }) {
  function validate() {
    const errs = {}
    if (!form.emergency_contact_name.trim()) errs.emergency_contact_name = 'Required'
    if (!form.emergency_contact_phone.trim()) errs.emergency_contact_phone = 'Required'
    return errs
  }

  function handleNext(e) {
    e.preventDefault()
    const errs = validate()
    if (Object.keys(errs).length) { onNext(errs); return }
    onNext({})
  }

  return (
    <form onSubmit={handleNext}>
      <div className="field" style={{ marginBottom: 14 }}>
        <label>Home address</label>
        <input type="text" value={form.address} onChange={e => setField('address', e.target.value)} placeholder="Street address, suburb, state, postcode" />
        <div style={{ fontSize: 11, color: '#666', marginTop: 4 }}>Used for billing and communication only.</div>
      </div>

      <div style={{ marginBottom: 6, paddingTop: 8, borderTop: '1px solid #222' }}>
        <div style={{ fontSize: 12, fontWeight: 700, color: '#888', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 12 }}>Emergency Contact</div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 14 }}>
        <div className="field">
          <label>Contact name</label>
          <input type="text" value={form.emergency_contact_name} onChange={e => setField('emergency_contact_name', e.target.value)} placeholder="Full name" required />
          {errors.emergency_contact_name && <div className="error-msg" style={{ marginTop: 4, fontSize: 12 }}>{errors.emergency_contact_name}</div>}
        </div>
        <div className="field">
          <label>Contact phone</label>
          <input type="tel" value={form.emergency_contact_phone} onChange={e => setField('emergency_contact_phone', e.target.value)} placeholder="04xx xxx xxx" required />
          {errors.emergency_contact_phone && <div className="error-msg" style={{ marginTop: 4, fontSize: 12 }}>{errors.emergency_contact_phone}</div>}
        </div>
      </div>

      <div style={{ display: 'flex', gap: 10, marginTop: 4 }}>
        <button type="button" className="btn btn-ghost" style={{ flex: 1 }} onClick={onBack}>← Back</button>
        <button type="submit" className="btn btn-lime" style={{ flex: 2 }}>Continue →</button>
      </div>
    </form>
  )
}

function Step3({ form, setField, onSubmit, onBack, loading, errors }) {
  return (
    <form onSubmit={onSubmit}>
      {errors.general && <div className="error-msg" style={{ marginBottom: 12 }}>{errors.general}</div>}

      <div style={{
        background: '#111', border: '1px solid #222', borderRadius: 8,
        padding: '14px 16px', maxHeight: 240, overflowY: 'auto',
        fontSize: 12, color: '#888', lineHeight: 1.6, marginBottom: 16,
        whiteSpace: 'pre-wrap',
      }}>
        {WAIVER_TEXT}
      </div>

      <div className="field" style={{ marginBottom: 14 }}>
        <label>Full name (type to sign)</label>
        <input
          type="text"
          value={form.signature}
          onChange={e => setField('signature', e.target.value)}
          placeholder={`${form.first_name} ${form.last_name}`}
          required
        />
        <div style={{ fontSize: 11, color: '#666', marginTop: 4 }}>Type your full name to confirm your digital signature.</div>
      </div>

      <label style={{ display: 'flex', alignItems: 'flex-start', gap: 10, marginBottom: 16, cursor: 'pointer' }}>
        <input
          type="checkbox"
          checked={form.waiver_agreed}
          onChange={e => setField('waiver_agreed', e.target.checked)}
          style={{ marginTop: 2, accentColor: '#ccff00', flexShrink: 0 }}
          required
        />
        <span style={{ fontSize: 13, color: '#aaa', lineHeight: 1.5 }}>
          I have read and agree to the studio waiver, code of conduct, and cancellation policy. I confirm that I am 18 years of age or older.
        </span>
      </label>

      <div style={{ display: 'flex', gap: 10, marginTop: 4 }}>
        <button type="button" className="btn btn-ghost" style={{ flex: 1 }} onClick={onBack} disabled={loading}>← Back</button>
        <button
          type="submit"
          className="btn btn-lime"
          style={{ flex: 2 }}
          disabled={loading || !form.waiver_agreed || !form.signature.trim()}
        >
          {loading ? <span className="spinner" /> : 'Create account'}
        </button>
      </div>
    </form>
  )
}

export default function SignupPage() {
  const { login } = useAuth()
  const navigate = useNavigate()
  const location = useLocation()
  const from = location.state?.from || null

  const [step, setStep] = useState(1)
  const [errors, setErrors] = useState({})
  const [loading, setLoading] = useState(false)

  const [form, setFormState] = useState({
    first_name: '',
    last_name: '',
    email: '',
    password: '',
    date_of_birth: '',
    phone: '',
    address: '',
    emergency_contact_name: '',
    emergency_contact_phone: '',
    signature: '',
    waiver_agreed: false,
  })

  function setField(key, val) {
    setFormState(f => ({ ...f, [key]: val }))
    setErrors(e => ({ ...e, [key]: null }))
  }

  function handleStep1Next(errs) {
    if (Object.keys(errs).length) { setErrors(errs); return }
    setErrors({})
    setStep(2)
  }

  function handleStep2Next(errs) {
    if (Object.keys(errs).length) { setErrors(errs); return }
    setErrors({})
    setStep(3)
  }

  async function handleSubmit(e) {
    e.preventDefault()
    if (!form.waiver_agreed || !form.signature.trim()) return
    setLoading(true)
    setErrors({})
    try {
      await auth.register({
        first_name: form.first_name,
        last_name: form.last_name,
        email: form.email,
        password: form.password,
        date_of_birth: form.date_of_birth,
        phone: form.phone,
        address: form.address,
        emergency_contact_name: form.emergency_contact_name,
        emergency_contact_phone: form.emergency_contact_phone,
      })
      const me = await login(form.email, form.password)
      // Submit waiver form after login
      try {
        await forms.submit('waiver', {
          signature: form.signature,
          agreed: true,
          signed_at: new Date().toISOString(),
        })
      } catch { /* best effort */ }
      if (from && me.role === 'student') navigate(from)
      else navigate('/portal')
    } catch (err) {
      const data = err.response?.data || {}
      if (typeof data === 'object' && !data.detail) {
        setErrors(data)
        if (data.email || data.password) setStep(1)
      } else {
        setErrors({ general: data.detail || 'Could not create account — please try again.' })
      }
    } finally {
      setLoading(false)
    }
  }

  const stepLabels = ['Account', 'Details', 'Waiver']

  return (
    <div className="login-page">
      <div className="login-card" style={{ maxWidth: 460 }}>
        <div className="login-logo">DUALITY</div>

        {/* Step indicator */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8, marginBottom: 24 }}>
          {stepLabels.map((label, i) => {
            const n = i + 1
            const active = n === step
            const done = n < step
            return (
              <div key={n} style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                  <div style={{
                    width: 24, height: 24, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: 11, fontWeight: 700,
                    background: done ? '#ccff00' : active ? 'rgba(204,255,0,0.2)' : '#222',
                    color: done ? '#000' : active ? '#ccff00' : '#555',
                    border: active ? '1px solid #ccff00' : done ? 'none' : '1px solid #333',
                  }}>
                    {done ? '✓' : n}
                  </div>
                  <span style={{ fontSize: 11, color: active ? '#ccff00' : done ? '#888' : '#555', fontWeight: active ? 700 : 400 }}>
                    {label}
                  </span>
                </div>
                {i < stepLabels.length - 1 && <div style={{ width: 20, height: 1, background: '#333' }} />}
              </div>
            )
          })}
        </div>

        {step === 1 && (
          <Step1 form={form} setField={setField} onNext={handleStep1Next} errors={errors} />
        )}
        {step === 2 && (
          <Step2 form={form} setField={setField} onNext={handleStep2Next} onBack={() => setStep(1)} errors={errors} />
        )}
        {step === 3 && (
          <Step3 form={form} setField={setField} onSubmit={handleSubmit} onBack={() => setStep(2)} loading={loading} errors={errors} />
        )}

        <p className="login-help" style={{ marginTop: 16 }}>
          Already have an account?{' '}
          <Link to="/login" state={from ? { from } : undefined} style={{ color: '#ccff00' }}>
            Sign in
          </Link>
        </p>
      </div>
    </div>
  )
}

